pub unsafe extern "C" fn delete_user(mut u: *mut User) {
    if !u.is_null() {
        free((*u).session_token as *mut core::ffi::c_void);
        free(u as *mut core::ffi::c_void);
    }
}
</unsafe_rust_function>

