void	strip(char *str, char *comment)
{	/* removes trailing space, comment and
	   newline and copies it to comment */
	char	*c_ptr;

	comment[0] = '\0';
	c_ptr = strchr(str,'%');
	if (c_ptr == NULL) c_ptr = strchr(str,'\n');
	while (c_ptr > str && (*(c_ptr-1) == ' ' || *(c_ptr-1) == '\t'))
		--c_ptr;
	if (c_ptr) {
		(void) strcpy(comment,c_ptr);
		*c_ptr = '\0';
	}
}

