    *((*pdf).xrefs).offset(0 as core::ffi::c_int as isize) = *((*pdf).xrefs)
        .offset(1 as core::ffi::c_int as isize);
    *((*pdf).xrefs).offset(1 as core::ffi::c_int as isize) = buf;
    (*((*pdf).xrefs).offset(0 as core::ffi::c_int as isize)).is_linear = 1
