    let mut pos_count: core::ffi::c_long = 0;
    let mut x: core::ffi::c_char = 0;
    let mut c: *mut core::ffi::c_char = 0 as *mut core::ffi::c_char;
    let mut buf: [core::ffi::c_char; 256] = [0; 256];
