    (*pdf).n_xrefs = 0 as core::ffi::c_int;
    fseek(fp, 0 as core::ffi::c_long, SEEK_SET);
    while get_next_eof(fp) >= 0 as core::ffi::c_int {
        (*pdf).n_xrefs += 1;
    }
    if (*pdf).n_xrefs == 0 {
        return 0 as core::ffi::c_int;
    }
